+
+export const stylePromptTitle = (title?: string): string | undefined =>
+  title && isRich() ? theme.heading(title) : title;
+
+export const stylePromptHint = (hint?: string): string | undefined =>
+  hint && isRich() ? theme.muted(hint) : hint;

